void SetTextMode()

{

   if(textMode==0)

   {

      parki[1]=2;      //parki ptaszkow pasujacych do siebie

      parki[2]=1;

      parki[3]=4;

      parki[4]=3;

      parki[5]=6;

      parki[6]=5;

      parki[7]=8;

      parki[8]=7;

      parki[9]=10;

      parki[10]=9;

      parki[11]=12;

      parki[12]=11;

      parki[13]=14;

      parki[14]=13;

      parki[15]=16;

      parki[16]=15;

      parki[17]=18;

      parki[18]=17;

      parki[19]=20;

      parki[20]=19;

      parki[21]=22;

      parki[22]=21;

      parki[23]=24;

      parki[24]=23;

      parki[25]=26;

      parki[26]=25;



      playStatus = 0;

      Sound_Holder.Stop(0);

      Text_Holder.HideText(0);

      Text_Holder.StopSynchroText(0);

      Sound_Holder.SetPlayDSoundParameters(1,0,0,0);

   }

   else

   {

      int index = 1;

      while( index < 53 )

      {

         Transparent_Video_Holder.ResetVideo(index);

         index++;

      }





      playStatus = 1;   

      Sound_Holder.SetPlayDSoundParameters(1,-1000,0,0);

      Sound_Holder.PlayDSound(0);

      Text_Holder.SetTextOffsets(0,0,0);

      Text_Holder.DisableMouse(0);

      Text_Holder.ShowText(0);

   }

}











void Transparent_Video_Holder.MouseMoveIn(int videoID)

{

   if( textMode || action) return;



   if((parki[videoID] && videoID!=lastClick) || (videoID==0))   

      SetCursor(1);

}





void Transparent_Video_Holder.MouseMoveOut(int videoID)

{

   SetCursor(0);

}





void Transparent_Video_Holder.MouseClickOnDown(int videoID)

{

   if( textMode || action) return;



   if(videoID)

   {

      if(parki[videoID]==0)   return;

      if(lastClick)

      {

         if(parki[videoID]==lastClick)

         {

            parki[videoID]=0;

            parki[lastClick]=0;

            Transparent_Video_Holder.Play(videoID,0);

            wygas=0;

         }

         else

         {

            Transparent_Video_Holder.Play(videoID+26,0);

            Transparent_Video_Holder.HideFirsLastVideoFrame(videoID);

            wygas=lastClick;

         }

         lastClick=0;

      }

      else

      {

         Transparent_Video_Holder.Play(videoID,0);

         lastClick=videoID;

      }   

      action = 1;

   }

   else   //to domek

      Transparent_Video_Holder.Play(videoID,0);

}





void Transparent_Video_Holder.TheEnd(int videoID)

{

   action = 0;

   if(videoID>26)

   {

      Transparent_Video_Holder.HideFirsLastVideoFrame(videoID);

      Transparent_Video_Holder.ShowFirsLastVideoFrame(videoID-26);

   }

   if(wygas)

   {

      Transparent_Video_Holder.ResetVideo(wygas);

      wygas=0;

   }

   int index = 1;

   int end=1;

   while(index < 27)

   {

      if(parki[index])  

      {

         end=0;

         break;

      }

      index++;

   }

   if(end)   //wszystkie odkryto

      Sound_Holder.PlayDSound(2);

}





